def extract_text_from_pdf(pdf_bytes: bytes) -> str:
    MSG = "Could not extract text from the PDF. The file may be corrupted or image-only."

    try:
        reader = PdfReader(BytesIO(pdf_bytes))
        parts = []
        for page in reader.pages:
            text = page.extract_text()
            if text:
                parts.append(text)
        full_text = "\n".join(parts).strip()
    except Exception as e:
        raise PDFExtractionError(MSG) from e

    if not full_text:
        raise PDFExtractionError(MSG)

    return full_text

def get_api_key() -> str | None:
    # Try Streamlit secrets first (for Streamlit Cloud deployment)
    try:
        import streamlit as st
        key = st.secrets.get("DEEPSEEK_API_KEY", None)
        if key and key.strip() != "" and key != "your_api_key_here":
            return key
    except (ImportError, AttributeError):
        pass

    # Fall back to environment variable (for local dev with .env)
    key = os.getenv("DEEPSEEK_API_KEY")
    if not key or key.strip() == "" or key == "your_api_key_here":
        return None
    return key

def generate_match_report(
    resume_text: str, job_description: str, api_key: str | None = None
) -> str:
    # Use user-provided key first, then fall back to server-side secrets / env
    effective_key = api_key or get_api_key()
    if not effective_key:
        raise MissingAPIKeyError(
            "No API key configured. Enter your DeepSeek API key in the sidebar, "
            "or set DEEPSEEK_API_KEY on the server."
        )

    client = OpenAI(api_key=effective_key, base_url=DEEPSEEK_BASE_URL)

    try:
        response = client.chat.completions.create(
            model=DEEPSEEK_MODEL,
            messages=[
                {"role": "system", "content": SYSTEM_PROMPT},
                {"role": "user", "content": build_user_prompt(resume_text, job_description),}
            ],
            temperature=0.3,
            max_tokens=8192,
            extra_body={"thinking": {"type": "disabled"}}
        )
    except AuthenticationError as e:
        raise LLMError("Invalid API key. Check that you entered a valid DeepSeek API key.") from e
    except RateLimitError as e:
        raise LLMError("Rate limit exceeded. Please try again in a few minutes.") from e
    except APIError as e:
        raise LLMError(f"Analysis failed: {e.message}") from e

    content = response.choices[0].message.content
    if not content:
        raise LLMError("The model returned an empty response. Please try again.")

    return content
